def check_dict_case(dict):
    if not dict:
        return False

    all_lower = True
    all_upper = True

    for key in dict:
        if not isinstance(key, str):
            return False
        if key != key.lower():
            all_lower = False
        if key != key.upper():
            all_upper = False

    return all_lower or all_upper
